export { FormTextField } from './form_text_field';
```

### **`form.tsx` (Container Component)**
```typescript
import type { FormEvent, ReactNode } from 'react';
import './form.scss';

interface FormProps {
  children: ReactNode;
  onSubmit?: () => void;
}

export function Form({ children, onSubmit }: FormProps) {
  function handleSubmit(e: FormEvent) {
    e.preventDefault();
  }

  function handleKeyDown(e: React.KeyboardEvent) {
    if (e.key === 'Enter' && e.metaKey && onSubmit) {
      e.preventDefault();
      onSubmit();
    }
  }

  return (
    <form
      className="form"
      onSubmit={handleSubmit}
      onKeyDown={handleKeyDown}
      noValidate
    >
      <div className="form__fields">{children}</div>
    </form>
  );
}
```

### **Key Observations**

1. **No Separator/Divider Component Exists** - There is no `form_separator.tsx` or `form_divider.tsx` in the directory.

2. **Component Pattern** - All form field components follow this structure:
   - Use `useId()` for unique IDs
   - Wrap in `<FormField>` component for consistent styling/layout
   - Pass `label`, `description`, `error`, `htmlFor` to FormField
   - Implement `onChange` callback for state management
   - Support `error` and `description` optional props
   - Use proper `aria-` attributes for accessibility

3. **FormField Base Component** - The wrapper that provides:
   - Label rendering
   - Error display (replaces description when present)
   - Description text support
   - Consistent flex layout with `gap: $space-1`

4. **Styling Pattern** - All use:
   - `.form-input` base class for inputs
   - `.form-input--[variant]` modifiers (e.g., `--select`, `--textarea`, `--date`)
   - SCSS tokens imported from `../../styles/tokens`
   - Individual `.scss` files for complex components

5. **Gap Structure** - Form uses:
   - `.form__fields` container with `gap: $space-4` between fields
   - Form itself has `padding: $space-3` and `overflow-y: auto`

